module top_module(
    input [31:0]data_in_0,in1,in2,in3,
    input [1:0]select,
    output reg [31:0]out
    );always @ (*)
    begin
        case (select)
            2'b00:out=data_in_0;
            2'b01:out=in1;
            2'b10:out=in2;
            2'b11:out=in3;
        endcase
    end

endmodule
